#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unaccent;

sub extract_data {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    for (my $page = 1; $page <= $pdf->pages; $page++) {
        my $text = $pdf->page($page)->text();
        print "Page $page:\n$text\n";
    }
}

sub extract_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $info = $pdf->info();
    print "Author: " . $info->{'/Author'} . "\n";
    print "Title: " . $info->{'/Title'} . "\n";
    print "Creation Date: " . $info->{'/CreationDate'} . "\n";
}

sub extract_tables {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    for (my $page = 1; $page <= $pdf->pages; $page++) {
        my $content = $pdf->page($page)->content();
        if ($content =~ /Tabl(e|e)/i) {
            print "Table found on page $page:\n$content\n";
        }
    }
}

extract_data('example.pdf');
extract_info('example.pdf');
extract_tables('example.pdf');
